    14→  ({ $round, theme: { color, borderRadius } }) => css`
    15→    display: flex;
    16→    cursor: pointer;
    17→    position: relative;
    18→    flex-direction: ${$round ? 'column' : 'row'};
    19→    align-items: ${$round ? 'center' : 'start'};
    20→    border-radius: ${borderRadius.s};
    21→    background: ${$round ? color.cardBackground : 'transparent'};
    22→    height: 100%;
    23→    width: 100%;
    24→    min-width: 50px;
    25→    max-width: ${$round ? '200px' : 'auto'};
    26→    max-height: ${$round ? '200px' : '309px'};
    27→    margin: 0;
    28→    padding: ${$round ? '1.5rem 2rem' : '0'};
    29→
    30→    &:hover {
    31→      opacity: 0.9;
    32→    }
    33→
    34→    @media ${breakpoints.M} {
    35→      padding: ${$round ? '1.5rem 0' : '0'};
    36→    }
    37→  `
    38→)
    39→
    40→const Image = styled.img(
    41→  ({ theme: { borderRadius } }) => css`
    42→    object-fit: cover;
    43→    width: auto;
    44→    border-radius: ${borderRadius.s};
    45→    width: 100%;
    46→    height: 100%;
    47→    min-width: 50px;
    48→    min-height: 50px;
    49→    max-height: 300px;
    50→  `
    51→)
    52→
    53→const RoundImage = styled(Image)(
    54→  ({ theme: { borderRadius } }) => css`
    55→    border-radius: ${borderRadius.round};
    56→    width: 4.5rem;
    57→    height: 4.5rem;
    58→    min-width: 4.5rem;
    59→    min-height: 4.5rem;
    60→    max-height: 200px;
    61→    @media ${breakpoints.M} {
    62→      width: 6.5rem;
    63→      height: 6.5rem;
    64→      min-width: 6.5rem;
    65→      min-height: 6.5rem;
    66→    }
    67→  `
    68→)
    69→
    70→const FloatingTitle = styled.figcaption(
    71→  ({ theme: { color, borderRadius } }) => css`
    72→    position: absolute;
    73→    top: 1.5rem;
    74→    left: 1.5rem;
    75→    border-radius: ${borderRadius.s};
    76→    background: #202020;
    77→    padding: 8px 16px;
    78→    text-shadow: 2px 1px 2px rgba(0, 0, 0, 0.5);
    79→    span {
    80→      color: ${color.white};
    81→    }
    82→  `
    83→)
    84→
    85→const Title = styled.figcaption`
    86→  padding-top: 1rem;
    87→`
    88→
    89→const Rounded = ({ title, photoUrl: url }: CategoryProps) => (
    90→  <>
    91→    <RoundImage src={url} alt="restaurant category" />
    92→    <Title>
    93→      <Body type="span">{title}</Body>
    94→    </Title>
    95→  </>
    96→)
    97→
    98→const Squared = ({ title, photoUrl: url }: CategoryProps) => (
    99→  <>
   100→    <Image src={url} alt="restaurant category" />
   101→    <FloatingTitle>
   102→      <Body type="span" fontWeight="medium">
   103→        {title}
   104→      </Body>
   105→    </FloatingTitle>
   106→  </>
   107→)
   108→
   109→export const Category = ({ photoUrl, title, round = false }: CategoryProps) => {
   110→  return (
   111→    <Container $round={round} data-testid={title}>
   112→      {round ? (
   113→        <Rounded photoUrl={photoUrl} title={title} />
   114→      ) : (
   115→        <Squared photoUrl={photoUrl} title={title} />
   116→      )}
   117→    </Container>
   118→  )
   119→}
